## еҫ—зӣҠдәҺAIжҠҖжңҜзҡ„жҷ®еҸҠпјҢи®©жҲ‘иҝҷдёӘйқһдё“дёҡйҖүжүӢд№ҹиғҪе®һзҺ°дҪҝз”ЁpythonејҖеҸ‘еҮәиҮӘе·ұжғіиҰҒзҡ„еҠҹиғҪ
### еңЁжӯӨи®°еҪ•иҙҙеҮәд»Јз Ғз”ЁдҪңеӨҮд»Ҫзҡ„ 
### ж— иҮӘеҠЁеӣһеӨҚеҠҹиғҪзүҲ 
```python
import os
import time
import tkinter as tk
from tkinter import scrolledtext, messagebox
import requests
import json
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler
import threading
import wxauto
import win32clipboard
import pythoncom


class DumpFileHandler(FileSystemEventHandler):
    def __init__(self, text_widget, upload_callback):
        self.text_widget = text_widget
        self.upload_callback = upload_callback
        self.event_processed = {}  

    def on_created(self, event):
        self.handle_event(event, 'ж–°ж–Үд»¶еҲӣе»ә')

    def on_modified(self, event):
        self.handle_event(event, 'ж–Үд»¶дҝ®ж”№')

    def on_deleted(self, event):
        self.handle_event(event, 'ж–Үд»¶еҲ йҷӨ')

    def handle_event(self, event, event_type):
        if event.is_directory:
            return
        file_path = event.src_path
        if file_path.endswith(('.dump', '.bin', '.txt')):
            if file_path not in self.event_processed:
                self.text_widget.insert(tk.END, f'{event_type}: {file_path}\n')
                self.text_widget.yview(tk.END)
                self.upload_callback(filepath=file_path)  
                self.event_processed[file_path] = True
            else:
                print(f'е·ІеӨ„зҗҶиҝҮ {file_path} зҡ„{event_type}дәӢд»¶пјҢи·іиҝҮйҮҚеӨҚеӨ„зҗҶ')


def upload(filepath: str) -> str:
    url = 'http://47.98.235.44:5005/upload'
    try:
        with open(filepath, 'rb') as file:
            files = [
                ('upload_dump', (os.path.basename(filepath), file, 'application/octet-stream'))
            ]
            response = requests.post(url, files=files)
            if response.status_code == 200:
                return response.text
            else:
                raise Exception(f'Upload failed with status code {response.status_code}')
    except Exception as e:
        raise Exception(f'Error uploading file: {str(e)}')


def analysis(uuid: str) -> str:
    url = 'http://47.98.235.44:5005/analysis'
    payload = json.dumps({'uuid': uuid})
    headers = {
        'Content-Type': 'application/json'
    }
    try:
        response = requests.post(url, headers=headers, data=payload)
        if response.status_code == 200:
            return response.text
        else:
            raise Exception(f'Analysis request failed with status code {response.status_code}')
    except Exception as e:
        raise Exception(f'Error sending analysis request: {str(e)}')


def copy_to_clipboard(output_text: tk.Text):
    try:
        root.clipboard_clear()
        result = output_text.get(1.0, tk.END).strip()
        root.clipboard_append(result)
        output_text.insert(tk.END, 'еҲҶжһҗз»“жһңе·ІеӨҚеҲ¶еҲ°еүӘиҙҙжқҝ\n')
    except Exception as e:
        output_text.insert(tk.END, f'й”ҷиҜҜ: еӨҚеҲ¶еҲ°еүӘиҙҙboardж—¶еҸ‘з”ҹй”ҷиҜҜ: {str(e)}\n')


def process_file(filepath: str, output_text: tk.Text, target_group_name):
    def build_message(data):
        messages = []
        if data and data[0]:
            for item in data[0]:
                if isinstance(item, dict):
                    name = item.get('name', '')
                    values = item.get('value', [])
                    for value in values:
                        if isinstance(value, dict):
                            b = value.get('b', '')
                            messages.append(f'{name}: {b}')
        return '\n'.join(messages) if messages else None

    def handle_analysis_result(analysis_data):
        if analysis_data.get('code') == 200:
            data = analysis_data.get('data', [])
            result_message = build_message(data)
            if result_message:
                output_text.delete(1.0, tk.END)
                output_text.insert(tk.END, f'и§ЈжһҗжҲҗеҠҹпјҢиҝ”еӣһж•°жҚ®:\n{result_message}\n')
                copy_to_clipboard(output_text)
                send_to_wechat(result_message, target_group_name)  # и°ғз”ЁеҸ‘йҖҒеҫ®дҝЎж¶ҲжҒҜзҡ„еҮҪж•°е№¶дј е…ҘзҫӨеҗҚз§°
                return result_message
            else:
                warning_message = 'иҜҘж•°жҚ®жҡӮжңӘж”¶еҪ•'
                output_text.delete(1.0, tk.END)
                output_text.insert(tk.END, warning_message + '\n')
                copy_to_clipboard(output_text)
                send_to_wechat(warning_message, target_group_name)  # и°ғз”ЁеҸ‘йҖҒеҫ®дҝЎж¶ҲжҒҜзҡ„еҮҪж•°е№¶дј е…ҘзҫӨеҗҚз§°
                return warning_message
        else:
            warning_message = f'иӯҰе‘Ҡ: и§ЈжһҗеӨұиҙҘ: {analysis_data.get('message')}\n'
            output_text.delete(1.0, tk.END)
            output_text.insert(tk.END, warning_message)
            copy_to_clipboard(output_text)
            send_to_wechat(warning_message, target_group_name)  # и°ғз”ЁеҸ‘йҖҒеҫ®дҝЎж¶ҲжҒҜзҡ„еҮҪж•°е№¶дј е…ҘзҫӨеҗҚз§°
            return warning_message

    def handle_file_deletion(filepath):
        import subprocess
        import sys
        if sys.platform.startswith('win32'):
            command = f'del /f /q '{filepath}''
        else:
            command = f'rm -f '{filepath}''
        try:
            subprocess.run(command, shell=True, check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
            output_text.insert(tk.END, f'ж–Үд»¶ {filepath} е·ІжҲҗеҠҹеҲ йҷӨ\n')
        except subprocess.CalledProcessError as e:
            output_text.insert(tk.END, f'й”ҷиҜҜ: еҲ йҷӨж–Үд»¶ {filepath} ж—¶еҮәй”ҷ: {str(e)}\n')
        except Exception as e:
            output_text.insert(tk.END, f'е…¶д»–й”ҷиҜҜ: {str(e)}\n')

    try:
        result = upload(filepath)
        response_data = json.loads(result)
        uuid = response_data.get('uuid')
        if uuid:
            analysis_result = analysis(uuid)
            analysis_data = json.loads(analysis_result)
            message = handle_analysis_result(analysis_data)
            handle_file_deletion(filepath)
        else:
            warning_message = 'иӯҰе‘Ҡ: жңӘиғҪиҺ·еҸ–UUID\n'
            output_text.delete(1.0, tk.END)
            output_text.insert(tk.END, warning_message)
            copy_to_clipboard(output_text)
            send_to_wechat(warning_message, target_group_name)  # и°ғз”ЁеҸ‘йҖҒеҫ®дҝЎж¶ҲжҒҜзҡ„еҮҪж•°е№¶дј е…ҘзҫӨеҗҚз§°
    except json.JSONDecodeError:
        output_text.delete(1.0, tk.END)
        output_text.insert(tk.END, 'й”ҷиҜҜ: иҝ”еӣһж•°жҚ®ж јејҸй”ҷиҜҜпјҢж— жі•и§ЈжһҗJSON\n')
        send_to_wechat('й”ҷиҜҜ: иҝ”еӣһж•°жҚ®ж јејҸй”ҷиҜҜпјҢж— жі•и§ЈжһҗJSON\n', target_group_name)  # и°ғз”ЁеҸ‘йҖҒеҫ®дҝЎж¶ҲжҒҜзҡ„еҮҪж•°е№¶дј е…ҘзҫӨеҗҚз§°
    except Exception as e:
        output_text.delete(1.0, tk.END)
        output_text.insert(tk.END, f'й”ҷиҜҜ: еҸ‘з”ҹй”ҷиҜҜ: {str(e)}\n')
        send_to_wechat(f'й”ҷиҜҜ: еҸ‘з”ҹй”ҷиҜҜ: {str(e)}\n', target_group_name)  # и°ғз”ЁеҸ‘йҖҒеҫ®дҝЎж¶ҲжҒҜзҡ„еҮҪж•°е№¶дј е…ҘзҫӨеҗҚз§°


class MonitorApp:
    def __init__(self, master):
        self.master = master
        self.master.title('ж–Үд»¶зӣ‘жҺ§е·Ҙе…·')
        self.master.geometry('500x450')  # еўһеҠ й«ҳеәҰд»Ҙе®№зәіж–°з»„д»¶

        self.label_group = tk.Label(master, text='зӣ®ж ҮзҫӨеҗҚз§°:')  # ж–°еўһж Үзӯҫ
        self.label_group.pack(pady=10)

        self.group_entry = tk.Entry(master, width=50)  # ж–°еўһиҫ“е…ҘжЎҶ
        self.group_entry.pack(pady=10)

        self.label = tk.Label(master, text='зӣ‘жҺ§зӣ®еҪ•:')
        self.label.pack(pady=10)

        self.directory_entry = tk.Entry(master, width=50)
        self.directory_entry.pack(pady=10)

        self.start_button = tk.Button(master, text='ејҖе§Ӣзӣ‘жҺ§', command=self.start_monitoring)
        self.start_button.pack(pady=10)

        self.stop_button = tk.Button(master, text='еҒңжӯўзӣ‘жҺ§', command=self.stop_monitoring)
        self.stop_button.pack(pady=10)

        self.output_text = scrolledtext.ScrolledText(master, width=60, height=15)
        self.output_text.pack(pady=10)

        self.observer = None
        self.is_running = False

    def start_monitoring(self):
        group_name = self.group_entry.get().strip()  # иҺ·еҸ–зҫӨеҗҚз§°
        directory = self.directory_entry.get().strip()
        if not os.path.isdir(directory):
            messagebox.showerror('й”ҷиҜҜ', 'иҜ·иҫ“е…Ҙжңүж•Ҳзҡ„зӣ®еҪ•и·Ҝеҫ„пјҒ')
            return

        self.is_running = True
        self.output_text.insert(tk.END, f'ејҖе§Ӣзӣ‘жҺ§зӣ®еҪ•: {directory}\n')
        self.output_text.yview(tk.END)

        event_handler = DumpFileHandler(self.output_text, lambda filepath: process_file(filepath, self.output_text, group_name))  # дј е…ҘзҫӨеҗҚз§°
        self.observer = Observer()
        self.observer.schedule(event_handler, directory, recursive=False)
        self.observer.start()
        threading.Thread(target=self.run_observer, daemon=True).start()

    def run_observer(self):
        try:
            while self.is_running:
                time.sleep(1)
        except Exception as e:
            self.output_text.insert(tk.END, f'зӣ‘жҺ§еҮәй”ҷ: {str(e)}\n')
            self.output_text.yview(tk.END)

    def stop_monitoring(self):
        self.is_running = False
        if self.observer:
            self.observer.stop()
            self.observer.join()
        self.output_text.insert(tk.END, 'зӣ‘жҺ§е·ІеҒңжӯўгҖӮ
